import{_ as e,c as a,o as d,ae as r}from"./chunks/framework.BLa4S9S3.js";const p=JSON.parse('{"title":"Git 전략","description":"","frontmatter":{},"headers":[],"relativePath":"git-strategy.md","filePath":"git-strategy.md"}'),o={name:"git-strategy.md"};function i(l,t,c,s,n,u){return d(),a("div",null,t[0]||(t[0]=[r('<h1 id="git-전략" tabindex="-1">Git 전략 <a class="header-anchor" href="#git-전략" aria-label="Permalink to &quot;Git 전략&quot;">​</a></h1><p>이 문서는 Git 브랜치 전략, 브랜치 네이밍 규칙, 커밋 메시지 작성 컨벤션에 대해 정의합니다. 일관된 협업을 위해 <code>Trunk-based</code> 개발 방식을 따르며, 티켓 기반 브랜치 네이밍과 명확한 커밋 타입을 통해 가독성 높고 추적 가능한 Git 이력을 유지하는 것이 목적입니다.</p><nav class="table-of-contents"><ul><li><a href="#브랜치-전략">브랜치 전략</a></li><li><a href="#feature-브랜치-네이밍">feature 브랜치 네이밍</a></li><li><a href="#커밋-메시지-컨벤션">커밋 메시지 컨벤션</a></li></ul></nav><h2 id="브랜치-전략" tabindex="-1">브랜치 전략 <a class="header-anchor" href="#브랜치-전략" aria-label="Permalink to &quot;브랜치 전략&quot;">​</a></h2><blockquote><p>Trunk-based Development</p></blockquote><ul><li>main 브랜치에서 파생된, 짧은 수명의 feature 브랜치를 생성해 작업한다.</li><li>squash merge를 기본으로 하며, PR 병합 후 작업한 feature 브랜치는 삭제한다.</li></ul><h2 id="feature-브랜치-네이밍" tabindex="-1">feature 브랜치 네이밍 <a class="header-anchor" href="#feature-브랜치-네이밍" aria-label="Permalink to &quot;feature 브랜치 네이밍&quot;">​</a></h2><ul><li>형식 : feature/Y26W2-<code>&lt;티켓번호&gt;</code>-<code>&lt;상세기능&gt;</code></li><li>예시 : <code>feature/Y26W2-5-login</code>, <code>feature/Y26W2-32-dashboard-error</code></li></ul><h2 id="커밋-메시지-컨벤션" tabindex="-1">커밋 메시지 컨벤션 <a class="header-anchor" href="#커밋-메시지-컨벤션" aria-label="Permalink to &quot;커밋 메시지 컨벤션&quot;">​</a></h2><ul><li><p>pnpm commit을 사용하여 commit 메시지를 prompt에 따라 구성하거나,</p></li><li><p>spr을 활용할 경우, 하단의 컨벤션을 준수하여 커밋 메시지를 작성한다.</p></li></ul><p>형식: <code>[Y26W2-000] &lt;type&gt;(optional scope): &lt;description&gt;</code></p><p><strong>커밋 타입</strong></p><table tabindex="0"><thead><tr><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>feat</code></td><td>새로운 기능 추가</td></tr><tr><td><code>fix</code></td><td>버그 수정</td></tr><tr><td><code>docs</code></td><td>문서 수정 (README 등)</td></tr><tr><td><code>style</code></td><td>코드 스타일 수정 (세미콜론, 공백 등)</td></tr><tr><td><code>refactor</code></td><td>코드 리팩토링 (기능 변화 없음)</td></tr><tr><td><code>test</code></td><td>테스트 코드 추가/수정</td></tr><tr><td><code>chore</code></td><td>빌드, 설정, 패키지 등 기타 작업</td></tr><tr><td><code>perf</code></td><td>성능 개선</td></tr><tr><td><code>ci</code></td><td>CI 관련 변경</td></tr></tbody></table>',13)]))}const f=e(o,[["render",i]]);export{p as __pageData,f as default};
